	depWaiting, err := s.DependencyWaiting()
	require.NoError(t, err)
	found := false
	for _, b := range depWaiting {
		if b.ID == child.ID {
			found = true
		}
	}
	if !found {
		t.Errorf("child bead %s should appear in DependencyWaiting after parent cancelled but was absent", child.ID)
